# Basic output validation using Pydantic
# pip install anthropic pydantic

import json
import anthropic
from pydantic import BaseModel, field_validator, ValidationError
from dataclasses import dataclass
from typing import Optional

# --- Output contract ---
class ProductSummary(BaseModel):
    name: str
    price_usd: float
    in_stock: bool
    category: str

    @field_validator('price_usd')
    @classmethod
    def price_must_be_positive(cls, v: float) -> float:
        if v <= 0:
            raise ValueError('price_usd must be greater than zero')
        return round(v, 2)

    @field_validator('category')
    @classmethod
    def category_must_be_known(cls, v: str) -> str:
        allowed = {'electronics', 'clothing', 'food', 'books', 'other'}
        if v.lower() not in allowed:
            raise ValueError(f'category must be one of {allowed}')
        return v.lower()

# --- Validation result ---
@dataclass
class ValidationResult:
    passed: bool
    error_message: Optional[str] = None
    repaired_output: Optional[ProductSummary] = None

# --- Validator ---
def validate_product_summary(raw_text: str) -> ValidationResult:
    """Parse and validate LLM output as a ProductSummary."""
    # Repair step: strip markdown fences if present
    text = raw_text.strip()
    if text.startswith('```'):
        lines = text.splitlines()
        text = '\n'.join(lines[1:-1])

    # Parse JSON
    try:
        data = json.loads(text)
    except json.JSONDecodeError as e:
        return ValidationResult(passed=False, error_message=f'Invalid JSON: {e}')

    # Validate schema
    try:
        product = ProductSummary(**data)
        return ValidationResult(passed=True, repaired_output=product)
    except ValidationError as e:
        return ValidationResult(passed=False, error_message=str(e))

# --- Usage with retry ---
client = anthropic.Anthropic()

SYSTEM = """You are a product data extractor. Given a product description,
extract structured data and return ONLY a JSON object with these fields:
  name (string), price_usd (number), in_stock (boolean), category (string).
Do not wrap in markdown. Output only the JSON object."""

def extract_product(description: str, max_retries: int = 2) -> ProductSummary:
    messages = [{"role": "user", "content": description}]
    for attempt in range(max_retries + 1):
        response = client.messages.create(
            model="claude-3-5-haiku-20241022",
            max_tokens=256,
            system=SYSTEM,
            messages=messages,
        )
        raw = response.content[0].text
        result = validate_product_summary(raw)

        if result.passed:
            return result.repaired_output

        if attempt < max_retries:
            # Include error in retry prompt so the model can self-correct
            messages.append({"role": "assistant", "content": raw})
            messages.append({
                "role": "user",
                "content": f"That response failed validation: {result.error_message}. Please try again."
            })
        else:
            raise ValueError(f"Validation failed after {max_retries + 1} attempts: {result.error_message}")

product = extract_product("Sony WH-1000XM5 headphones, $349.99, available now in electronics")
print(product)

# Composable validation pipeline: schema, PII, length, and toxicity
import re
from dataclasses import dataclass
from typing import Callable, List, Optional

@dataclass
class ValidationResult:
    passed: bool
    validator_name: str
    error_message: Optional[str] = None
    repaired_text: Optional[str] = None

# PII validator using regex patterns
PII_PATTERNS = [
    (re.compile(r'\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b', re.IGNORECASE), 'email address'),
    (re.compile(r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b'), 'US phone number'),
    (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), 'SSN pattern'),
]

def pii_validator(text: str) -> ValidationResult:
    for pattern, label in PII_PATTERNS:
        if pattern.search(text):
            return ValidationResult(
                passed=False,
                validator_name='PIIValidator',
                error_message=f'Output contains a {label}; redact before delivery'
            )
    return ValidationResult(passed=True, validator_name='PIIValidator')


def length_validator(min_chars: int = 20, max_chars: int = 4000) -> Callable[[str], ValidationResult]:
    def _validate(text: str) -> ValidationResult:
        n = len(text)
        if n < min_chars:
            return ValidationResult(
                passed=False, validator_name='LengthValidator',
                error_message=f'Output too short: {n} chars (min {min_chars})'
            )
        if n > max_chars:
            # Repair: truncate at last sentence boundary
            truncated = text[:max_chars]
            last_period = truncated.rfind('.')
            repaired = truncated[:last_period + 1] if last_period > 0 else truncated
            return ValidationResult(
                passed=False, validator_name='LengthValidator',
                error_message=f'Truncated from {n} to {len(repaired)} chars',
                repaired_text=repaired
            )
        return ValidationResult(passed=True, validator_name='LengthValidator')
    return _validate


# Minimal keyword toxicity check (use a real ML classifier in production)
TOXIC_KEYWORDS = frozenset({'threaten', 'harm', 'murder', 'bomb'})

def toxicity_validator(text: str) -> ValidationResult:
    words = frozenset(re.findall(r'\b\w+\b', text.lower()))
    hits = words & TOXIC_KEYWORDS
    if hits:
        return ValidationResult(
            passed=False, validator_name='ToxicityValidator',
            error_message=f'Potentially harmful content: {hits}'
        )
    return ValidationResult(passed=True, validator_name='ToxicityValidator')


class ValidationPipeline:
    """Run validators in order; repair and continue or fail fast."""
    def __init__(self, validators: List[Callable[[str], ValidationResult]]):
        self.validators = validators

    def run(self, text: str) -> tuple[bool, str, list[ValidationResult]]:
        results: list[ValidationResult] = []
        current = text
        for validator in self.validators:
            result = validator(current)
            results.append(result)
            if not result.passed:
                if result.repaired_text:
                    # Accept repair and re-run this same validator
                    current = result.repaired_text
                    repaired_result = validator(current)
                    results.append(repaired_result)
                    if not repaired_result.passed:
                        return False, current, results
                else:
                    return False, current, results
        return True, current, results


# Usage
pipeline = ValidationPipeline([
    pii_validator,
    length_validator(min_chars=50, max_chars=2000),
    toxicity_validator,
])

raw_output = "Contact support at help@example.com for assistance with your order."
passed, final_text, results = pipeline.run(raw_output)
if not passed:
    failed = next(r for r in results if not r.passed)
    print(f"BLOCKED by {failed.validator_name}: {failed.error_message}")
else:
    print("APPROVED:", final_text)

# Production-style validation for a financial research agent
import re
import json
from pydantic import BaseModel, field_validator, ValidationError
from dataclasses import dataclass
from typing import Optional
import logging

logger = logging.getLogger(__name__)

class EarningsExtraction(BaseModel):
    company_ticker: str
    fiscal_quarter: str       # e.g. "Q3 2024"
    revenue_usd_millions: float
    eps_reported: float
    guidance_raised: bool
    key_risks: list[str]

    @field_validator('revenue_usd_millions')
    @classmethod
    def revenue_sanity(cls, v: float) -> float:
        if not (0 < v < 1_000_000):
            raise ValueError(f'Revenue {v}M is outside the plausible range (0, 1_000_000)')
        return round(v, 2)

    @field_validator('company_ticker')
    @classmethod
    def ticker_format(cls, v: str) -> str:
        if not re.match(r'^[A-Z]{1,5}$', v.strip()):
            raise ValueError(f'Ticker {v!r} must be 1-5 uppercase letters')
        return v.strip().upper()

    @field_validator('fiscal_quarter')
    @classmethod
    def quarter_format(cls, v: str) -> str:
        if not re.match(r'^Q[1-4] \d{4}$', v):
            raise ValueError(f'Fiscal quarter must be in format "Q1 2024", got {v!r}')
        return v


DISCLOSURE_PHRASES = [
    'past performance is not indicative',
    'this is not investment advice',
    'risk of loss',
]

def disclosure_validator(summary: str) -> bool:
    lower = summary.lower()
    return any(phrase in lower for phrase in DISCLOSURE_PHRASES)


@dataclass
class FinancialValidationResult:
    passed: bool
    extraction: Optional[EarningsExtraction] = None
    error_stage: Optional[str] = None
    error_detail: Optional[str] = None


def validate_financial_output(
    raw_json: str,
    summary: str,
    doc_id: str,
) -> FinancialValidationResult:
    # Stage 1: parse JSON
    try:
        data = json.loads(raw_json.strip())
    except json.JSONDecodeError as e:
        logger.warning('doc=%s stage=json_parse error=%s', doc_id, e)
        return FinancialValidationResult(
            passed=False, error_stage='json_parse', error_detail=str(e)
        )

    # Stage 2: schema + business constraints via Pydantic
    try:
        extraction = EarningsExtraction(**data)
    except ValidationError as e:
        logger.warning('doc=%s stage=schema_validation error=%s', doc_id, e)
        return FinancialValidationResult(
            passed=False, error_stage='schema_validation', error_detail=str(e)
        )

    # Stage 3: regulatory disclosure check
    if not disclosure_validator(summary):
        logger.warning('doc=%s stage=disclosure_check ticker=%s', doc_id, extraction.company_ticker)
        return FinancialValidationResult(
            passed=False,
            error_stage='disclosure_check',
            error_detail='Summary missing required risk disclosure paragraph'
        )

    logger.info('doc=%s validation=passed ticker=%s', doc_id, extraction.company_ticker)
    return FinancialValidationResult(passed=True, extraction=extraction)
